import requests
import json

def create_vhost(auth, vhost):
    url = "http://localhost:15672/api/vhosts/%s" % vhost
    resp = requests.put(url, auth=auth)
    return resp.status_code

def create_user(auth, user, password):
    url = 'http://localhost:15672/api/users/%s' % user
    headers = {'content-type': 'application/json'}
    payload = {'password': password, 'tags': ''}
    resp = requests.put(url, auth=auth, headers=headers, data=json.dumps(payload))
    return resp.status_code

def set_permissions(auth, vhost, user):
    url = 'http://localhost:15672/api/permissions/%s/%s' % (vhost, user)
    headers = {'content-type': 'application/json'}
    payload = {"configure": ".*", "write": ".*", "read": ".*"}
    resp = requests.put(url, auth=auth, headers=headers, data=json.dumps(payload))
    return resp.status_code

admin_auth = ('admin', 'password')  # Your RabbitMQ credentials
app_vhosts = ['app1', 'app2', 'app3'] # virtual hosts for different applications
users = [('user1', 'pass1'), ('user2', 'pass2'), ('user3', 'pass3')] # users for different applications

for app in app_vhosts:
    create_vhost(admin_auth, app)

for user, pwd in users:
    create_user(admin_auth, user, pwd)
    for vhost in app_vhosts:
        set_permissions(admin_auth, vhost, user)